import{_ as e,a as d,b as o,c as a,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as c,o as l,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/ocr.md","filePath":"ru-RU/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"ru-RU/Other/ocr.md"};function h(u,t,g,b,m,P){return l(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR извлекает текст из изображений, сканов и скриншотов документов.</p><p>После распознавания можно скопировать результат, экспортировать его как <code>Markdown</code>, <code>PDF</code> или <code>Word</code>, либо упаковать несколько форматов вместе для скачивания.</p><h2 id="что-умеет-ocr" tabindex="-1">Что умеет OCR <a class="header-anchor" href="#что-умеет-ocr" aria-label="Permalink to &quot;Что умеет OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Возможность</th><th>Описание</th></tr></thead><tbody><tr><td>Распознавание текста на изображении</td><td>Извлекает текст из изображений, скриншотов и сканов.</td></tr><tr><td>Распознавание структуры документа</td><td>Лучше подходит для таблиц, формул, печатей и смешанных text-image layouts.</td></tr><tr><td>Несколько сервисов</td><td>Поддерживает Baidu PaddleOCR, Microsoft Azure Vision и Google Vision.</td></tr><tr><td>Копирование результатов</td><td>Копирует распознанный текст после обработки.</td></tr><tr><td>Экспорт файлов</td><td>Экспортирует <code>Markdown</code>, <code>PDF</code> и <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>После распознавания нескольких файлов можно скачать результаты пакетом.</td></tr></tbody></table><h2 id="сначала-настроите-ocr-сервисы" tabindex="-1">Сначала настройте OCR-сервисы <a class="header-anchor" href="#сначала-настроите-ocr-сервисы" aria-label="Permalink to &quot;Сначала настройте OCR-сервисы&quot;">​</a></h2><p>Откройте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP-геолокация и OCR" loading="lazy"></p><p>Заполните credentials для сервисов, которые хотите использовать:</p><table tabindex="0"><thead><tr><th>Сервис</th><th>Что ввести</th><th>Лучше всего подходит для</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Рекомендуемый первый выбор. Хорошо работает с документами, изображениями, таблицами и смешанными layout.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> и <code>Azure Vision API Key</code></td><td>Полезно, если вы уже используете облачные сервисы Microsoft.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> используется только для quota query.</td><td>Полезно, если вы используете Google Cloud.</td></tr></tbody></table><p>После заполнения credentials сохраните настройки.</p><p>Для первого теста можно настроить только один сервис. Все три не нужны.</p><h2 id="настроика-google-vision" tabindex="-1">Настройка Google Vision <a class="header-anchor" href="#настроика-google-vision" aria-label="Permalink to &quot;Настройка Google Vision&quot;">​</a></h2><p>Настройка Google состоит из двух частей:</p><table tabindex="0"><thead><tr><th>Цель</th><th>Требование</th></tr></thead><tbody><tr><td>Использовать OCR</td><td>Включить <code>Cloud Vision API</code>, затем создать <code>API Key</code>.</td></tr><tr><td>Запрашивать usage</td><td>Создать service account, выдать <code>Monitoring Viewer</code>, затем скачать service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key и service account" loading="lazy"></p><h3 id="использование-google-для-ocr" tabindex="-1">Использование Google для OCR <a class="header-anchor" href="#использование-google-для-ocr" aria-label="Permalink to &quot;Использование Google для OCR&quot;">​</a></h3><ol><li>Откройте Google Cloud Console.</li><li>Перейдите в <code>APIs &amp; Services</code>.</li><li>Откройте <code>Library</code>, найдите <code>Cloud Vision API</code> и включите его.</li><li>Вернитесь в <code>Credentials</code>.</li><li>Создайте <code>API Key</code>.</li><li>Откройте API Key и скопируйте его.</li><li>Вставьте его в <code>Google Vision API Key</code> в ImgBed.</li><li>Сохраните.</li></ol><p>После этого в OCR-диалоге можно выбрать Google Vision.</p><h3 id="запрос-usage-google" tabindex="-1">Запрос usage Google <a class="header-anchor" href="#запрос-usage-google" aria-label="Permalink to &quot;Запрос usage Google&quot;">​</a></h3><p>Quota query не нужен для самого распознавания.</p><p>Он только примерно показывает, сколько вызовов Google Vision было использовано за последние 30 дней.</p><ol><li>В Google Cloud Console откройте <code>IAM &amp; Admin</code>.</li><li>Откройте <code>Service Accounts</code>.</li><li>Создайте service account, например <code>vision-monitor</code>.</li><li>Выдайте ему роль <code>Monitoring Viewer</code>.</li><li>Откройте детали service account и создайте key.</li><li>Выберите <code>JSON</code>.</li><li>Скачайте созданный JSON-файл.</li><li>Вернитесь в ImgBed и импортируйте его в service account <code>JSON</code> (необязательно).</li><li>После успешного импорта нажмите quota query.</li></ol><p>После импорта ImgBed показывает project name, которому принадлежит service account. При запросе usage ImgBed читает Google monitoring data и показывает количество вызовов за текущий месяц.</p><p>Коротко:</p><table tabindex="0"><thead><tr><th>Элемент</th><th>Назначение</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Выполняет OCR recognition.</td></tr><tr><td>Service account <code>JSON</code></td><td>Запрашивает, сколько вызовов Google Vision использовано.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Позволяет service account читать usage data.</td></tr></tbody></table><h2 id="получение-baidu-paddleocr-token" tabindex="-1">Получение Baidu PaddleOCR Token <a class="header-anchor" href="#получение-baidu-paddleocr-token" aria-label="Permalink to &quot;Получение Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR требует access token.</p><p><img src="'+d+'" alt="Получение PaddleOCR token" loading="lazy"></p><p>Откройте окно вызова <code>API</code> на странице Baidu PaddleOCR, нажмите получение token и скопируйте его.</p><p>Вернитесь в ImgBed, вставьте его в <code>PaddleOCR Token</code> и сохраните.</p><h2 id="запуск-распознавания" tabindex="-1">Запуск распознавания <a class="header-anchor" href="#запуск-распознавания" aria-label="Permalink to &quot;Запуск распознавания&quot;">​</a></h2><p>В File Management выберите изображение или скриншот документа и нажмите <code>OCR</code>.</p><p><img src="'+o+'" alt="OCR recognition" loading="lazy"></p><p>В диалоге выберите service и model.</p><p>Распространенные PaddleOCR models:</p><table tabindex="0"><thead><tr><th>Model</th><th>Лучше всего подходит для</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Рекомендуется по умолчанию. Хорошо для документов, таблиц, формул, печатей и смешанных layout.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Простые изображения, обычный текст и легкое распознавание.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Многоязычные, сложные изображения и chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Более сложные страницы документов и восстановление layout.</td></tr></tbody></table><p>Если не уверены, начните с <code>PP-StructureV3</code>.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Описание</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Используйте, когда изображение повернуто или перекошено.</td></tr><tr><td>Document flattening</td><td>Для сфотографированных документов с изгибом или наклоном.</td></tr><tr><td>Layout detection</td><td>Когда нужно сохранить headings, paragraphs, tables и структуру изображений.</td></tr><tr><td>Chart recognition</td><td>Когда изображение содержит charts или сложные структуры.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Делает экспортированный Markdown удобнее для чтения.</td></tr></tbody></table><p>Для обычных скриншотов оставляйте минимум опций. Для сканов документов включайте больше document-related options.</p><h2 id="просмотр-результатов" tabindex="-1">Просмотр результатов <a class="header-anchor" href="#просмотр-результатов" aria-label="Permalink to &quot;Просмотр результатов&quot;">​</a></h2><p>После завершения распознавания диалог показывает результат.</p><p>Его можно скопировать напрямую или выбрать форматы экспорта.</p><p><img src="'+a+'" alt="PDF recognition" loading="lazy"></p><p>Для страниц документов экспортированный <code>PDF</code> может сохранять внешний вид страницы и при этом оставлять текст пригодным для поиска. Это удобно для архивирования сканов и дальнейшего поиска содержимого.</p><h2 id="выбор-формата-экспорта" tabindex="-1">Выбор формата экспорта <a class="header-anchor" href="#выбор-формата-экспорта" aria-label="Permalink to &quot;Выбор формата экспорта&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Формат</th><th>Лучше всего для</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Заметки, документационные системы и дальнейшее редактирование.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Сохранение внешнего вида страницы и результатов сканированных документов.</td></tr><tr><td><code>Word (.docx)</code></td><td>Дальнейшее редактирование layout, изменение текста и передача другим.</td></tr><tr><td>Export all</td><td>Сохраняет несколько форматов и исходное изображение, подходит для важных архивов.</td></tr></tbody></table><p>Если нужен только текст, экспортируйте Markdown.</p><p>Если важен внешний вид страницы, используйте PDF или Word.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Экспортированные Word-документы можно открывать и редактировать в office software.</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>Некоторые документы содержат распознанные изображения, headings и paragraphs в Word output.</p><p>Качество распознавания зависит от четкости оригинала, выбора model и сложности документа.</p><h2 id="лучшие-типы-фаилов-для-ocr" tabindex="-1">Лучшие типы файлов для OCR <a class="header-anchor" href="#лучшие-типы-фаилов-для-ocr" aria-label="Permalink to &quot;Лучшие типы файлов для OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Тип файла</th><th>Рекомендация</th></tr></thead><tbody><tr><td>Четкие скриншоты</td><td>Распознавать напрямую.</td></tr><tr><td>Сканы</td><td>Лучше <code>PP-StructureV3</code>.</td></tr><tr><td>Сфотографированные документы</td><td>Включить orientation correction и document flattening.</td></tr><tr><td>Таблицы, формулы, печати</td><td>Лучше structured models.</td></tr><tr><td>Простые короткие текстовые изображения</td><td><code>PP-OCRv5</code> обычно достаточно.</td></tr></tbody></table><p>Более четкие изображения с ровным текстом обычно дают лучший результат.</p><h2 id="типичные-случаи" tabindex="-1">Типичные случаи <a class="header-anchor" href="#типичные-случаи" aria-label="Permalink to &quot;Типичные случаи&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Случай</th><th>Значение</th></tr></thead><tbody><tr><td>Recognition fails</td><td>Проверьте, сохранен ли service token или key.</td></tr><tr><td>Recognition is slow</td><td>Сложные документы и большие изображения требуют больше времени.</td></tr><tr><td>Table is incomplete</td><td>Попробуйте structured model.</td></tr><tr><td>Text has mistakes</td><td>Размытие, блики и перекос увеличивают ошибки. Попробуйте более четкое изображение.</td></tr><tr><td>Word output contains many images</td><td>Structured models могут сохранять часть распознанных изображений. Это нормально.</td></tr></tbody></table><h3 id="google-quota-query-fails" tabindex="-1">Google Quota Query Fails <a class="header-anchor" href="#google-quota-query-fails" aria-label="Permalink to &quot;Google Quota Query Fails&quot;">​</a></h3><p>Проверьте:</p><ol><li>Service account <code>JSON</code> импортирован.</li><li>Service account имеет роль <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> включен для проекта.</li></ol><p>Если нужен только OCR, а не usage query, service account JSON можно не использовать и заполнить только <code>Google Vision API Key</code>.</p><h2 id="короткии-сценарии" tabindex="-1">Короткий сценарий <a class="header-anchor" href="#короткии-сценарии" aria-label="Permalink to &quot;Короткий сценарий&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Открыть System Settings</span></span>
<span class="line"><span>-&gt; Открыть Other Settings</span></span>
<span class="line"><span>-&gt; Заполнить OCR service credentials</span></span>
<span class="line"><span>-&gt; Сохранить</span></span>
<span class="line"><span>-&gt; Вернуться в File Management</span></span>
<span class="line"><span>-&gt; Выбрать файл и нажать OCR</span></span>
<span class="line"><span>-&gt; Выбрать model</span></span>
<span class="line"><span>-&gt; Дождаться recognition</span></span>
<span class="line"><span>-&gt; Скопировать результат или экспортировать Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const q=c(p,[["render",h]]);export{k as __pageData,q as default};
